={{ 
  (() => {
    const raw = $fromAI('valor', 'valor pago') || '';
    const cleaned = raw.toString().replace(/[^\d.,]/g, '');

    if (cleaned.includes(',')) {
      return parseFloat(cleaned.replace(/\./g, '').replace(',', '.'));
    } else {
      return parseFloat(cleaned);
    }
  })() 
}}

={{
  (() => {
    const dataStr = $fromAI('data', 'data do pagamento') || '';

    if (!dataStr) return '';

    let dateISO = '';

    if (dataStr.includes('/')) {
      // Formato brasileiro: 07/07/2025 ou 07/07/2025 15:09
      const [datePart, timePart] = dataStr.split(' ');
      const [day, month, year] = datePart.split('/');
      dateISO = `${year}-${month}-${day}T${timePart || '00:00'}`;
    } else if (dataStr.includes('-')) {
      // Formato ISO: 2025-07-07
      const [datePart, timePart] = dataStr.split('T');
      dateISO = `${datePart}T${timePart || '00:00'}`;
    } else {
      return '';  // Se não reconhecido, retorna vazio
    }

    return new Date(dateISO).toISOString().substring(0,10);
  })()
}}

